// ─── RA-826: Build Qwen 3 14B prompt from recent workspace intel ─────────────
const response = $input.first().json;
const entries = response.entries || [];
const since   = response.since   || '7 days ago';

if (entries.length === 0) {
  console.log('RA-826: no workspace intel entries found for this week — skipping brief');
  return [{ json: { skip: true, reason: 'no_entries' } }];
}

// Build readable intel block
const lines = [`# Google Workspace Updates — last 7 days (${entries.length} entries)\n`];
for (const batch of entries) {
  for (const item of (batch.items || [])) {
    lines.push(`## ${item.title}`);
    lines.push(`Date: ${item.pub_date}`);
    lines.push(`URL: ${item.link}`);
    lines.push(`Keywords: ${(item.keywords_matched || []).join(', ')}`);
    lines.push(`Summary: ${item.summary}\n`);
  }
}
const intelBlock = lines.join('\n');

const systemPrompt = `You are a senior technology advisor briefing a founder. Write a concise executive brief on recent Google Workspace updates. Rules:
- Maximum 400 words
- Lead with the most strategically important items
- Flag anything directly relevant to: MCP integrations, AI agent workflows, NotebookLM, n8n automation
- No filler words. No "In summary". Direct, specific, actionable
- Format: 3-5 bullet points, each starting with an emoji that matches the type of update`;

const userPrompt = `Here are this week's Google Workspace updates:\n\n${intelBlock}\n\nWrite the weekly executive brief now.`;

console.log(`RA-826: preparing Qwen brief for ${entries.length} batches covering ${since}`);

return [{
  json: {
    skip:         false,
    entry_count:  entries.length,
    system:       systemPrompt,
    user:         userPrompt,
    since,
  }
}];

// ─── RA-826: Extract brief from Ollama response ──────────────────────────────
const ollamaRes = $input.first().json;

// Ollama /api/chat returns { message: { role, content }, ... }
const content = ollamaRes?.message?.content || ollamaRes?.choices?.[0]?.message?.content || '';
if (!content) {
  throw new Error(`Ollama returned empty content: ${JSON.stringify(ollamaRes)}`);
}

const today   = new Date().toISOString().split('T')[0];
const brief   = content.trim();
const message = `📋 *Weekly Workspace Update Brief — ${today}*\n\n${brief}\n\n_Source: workspaceupdates.googleblog.com via Pi-CEO RA-826_`;

console.log(`RA-826: brief generated (${brief.length} chars)`);

return [{ json: { brief, message, date: today } }];

const res = $input.first().json;
if (!res.ok) {
  throw new Error(`Telegram sendMessage failed: ${JSON.stringify(res)}`);
}
console.log(`✅ RA-826: weekly Workspace Update brief delivered to Telegram | message_id=${res.result?.message_id}`);
return [{ json: { success: true, message_id: res.result?.message_id } }];
